    id: 'ev-030', slug: 'appeal-to-women-2020',
    titleEn: "An Appeal to Women from Ukrainian Baptist Convention of the US",
    titleUk: 'Початок навчання для музикантів',
    publishedAtUk: '2019-12-06',
