    titleEn: 'Visiting the Church in Sacramento',
    titleUk: 'Хрещення в Ланкастері',
    publishedAtUk: '2017-10-17',
    publishedAt: '2018-12-13',
    thumbnailUrl: 'https://ukrbaptist.org/wp-content/uploads/2022/05/IMG_5679-768x714.jpg',
