    publishedAtUk: '2017-04-13',
    publishedAt: '2018-08-23',
    thumbnailUrl: 'https://ukrbaptist.org/wp-content/uploads/2022/05/73-ziizd_b3f1d5716abda1fe98d0cb62e4cb2cb8-768x549.jpg',
